import React from 'react';

export default function ResultModal({ result, onClose, onBackToLobby }) {
  if (!result) return null;

  const isWinner = result.isWinner;
  const isDraw = result.reason === 'draw' || result.reason === 'stalemate';

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content max-w-sm" onClick={(e) => e.stopPropagation()}>
        <div className="p-8 text-center">
          {/* Icon */}
          <div className={`w-20 h-20 mx-auto rounded-full flex items-center justify-center mb-5 animate-bounce-in ${
            isWinner
              ? 'bg-gradient-to-br from-gold-400 to-gold-600 shadow-lg shadow-gold-500/30'
              : isDraw
              ? 'bg-gradient-to-br from-slate-500 to-slate-600'
              : 'bg-gradient-to-br from-slate-700 to-slate-800'
          }`}>
            <span className="text-4xl">
              {isWinner ? '🏆' : isDraw ? '🤝' : '😔'}
            </span>
          </div>

          {/* Title */}
          <h2 className={`text-2xl font-black mb-2 ${
            isWinner ? 'text-gold-400' : isDraw ? 'text-slate-300' : 'text-slate-400'
          }`}>
            {isWinner ? 'Victory!' : isDraw ? 'Draw!' : 'Defeat'}
          </h2>

          <p className="text-slate-400 text-sm mb-6">
            {result.reason === 'checkmate' && (isWinner ? 'You checkmated your opponent!' : 'You were checkmated.')}
            {result.reason === 'timeout' && (isWinner ? 'Opponent ran out of time!' : 'You ran out of time.')}
            {result.reason === 'resigned' && (isWinner ? 'Opponent resigned.' : 'You resigned.')}
            {isDraw && 'The game ended in a draw.'}
            {!result.reason && (isWinner ? 'Congratulations!' : 'Better luck next time!')}
          </p>

          {/* Prize Won */}
          {result.prize > 0 && (
            <div className="mb-6 p-4 rounded-xl bg-gold-500/10 border border-gold-500/20 glow-gold">
              <p className="text-sm text-gold-400 mb-1">Prize Won</p>
              <p className="text-3xl font-black text-gold-300">₹{result.prize.toLocaleString()}</p>
              <p className="text-xs text-gold-500 mt-1">Added to your wallet</p>
            </div>
          )}

          {/* Winner info */}
          {result.winnerName && (
            <div className="mb-6 p-3 rounded-xl bg-navy-900/50 border border-navy-700/30">
              <p className="text-xs text-slate-500">Winner</p>
              <p className="text-white font-bold">{result.winnerName}</p>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-3">
            <button onClick={onClose} className="btn-secondary flex-1">
              View Bracket
            </button>
            <button onClick={onBackToLobby} className="btn-primary flex-1">
              Back to Lobby
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
